#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define MAX 100000
#define INF INT_MAX
// Structure to represent a graph
typedef struct {
    int **adj;
    int *dist;
    int V;
} Graph;
// Function to create a graph
Graph* createGraph(int V) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->V = V;
    graph->adj = (int**) malloc(V * sizeof(int*));
    for (int i = 0; i < V; i++) {
        graph->adj[i] = (int*) malloc(V * sizeof(int));
        for (int j = 0; j < V; j++) {
            graph->adj[i][j] = INF;
        }
    }
    return graph;
}
// Function to add an edge to the graph
void addEdge(Graph* graph, int u, int v, int w) {
    graph->adj[u][v] = w;
    graph->adj[v][u] = w;
}
// Function to perform BFS traversal
void bfs(Graph* graph, int s, int* dist) {
    int* visited = (int*) malloc(graph->V * sizeof(int));
    for (int i = 0; i < graph->V; i++) {
        visited[i] = 0;
    }
    dist[s] = 0;
    visited[s] = 1;
    int* queue = (int*) malloc(graph->V * sizeof(int));
    int front = 0, rear = 0;
    queue[rear++] = s;
    while (front < rear) {
        int u = queue[front++];
        for (int v = 0; v < graph->V; v++) {
            if (graph->adj[u][v] != INF && !visited[v]) {
                dist[v] = dist[u] + graph->adj[u][v];
                visited[v] = 1;
                queue[rear++] = v;
            }
        }
    }
    free(visited);
    free(queue);
}
int main() {
    int N;
    scanf("%d", &N);
    Graph* graph = createGraph(N);
    for (int i = 0; i < N - 1; i++) {
        int u, v, w;
        scanf("%d %d %d", &u, &v, &w);
        u--;
        v--;
        addEdge(graph, u, v, w);
    }
    int M;
    scanf("%d", &M);
    for (int i = 0; i < M; i++) {
        int S, F, P;
        scanf("%d %d %d", &S, &F, &P);
        S--;
        F--;
        int* dist = (int*) malloc(N * sizeof(int));
        for (int j = 0; j < N; j++) {
            dist[j] = INF;
        }
        bfs(graph, S, dist);
        int days = (dist[F] + P - 1) / P;
        printf("%d\n", days);
        free(dist);
    }
    return 0;
}

