#include <iostream>
#include <vector>
#include <queue>
#include <limits>
using namespace std;
#define MAX 100000
#define INF INT_MAX
// Structure to represent a graph
struct Graph {
    vector<vector<int>> adj;
    int V;
    Graph(int V) : V(V), adj(V, vector<int>(V, INF)) {}
};
// Function to add an edge to the graph
void addEdge(Graph& graph, int u, int v, int w) {
    graph.adj[u][v] = w;
    graph.adj[v][u] = w;
}
// Function to perform BFS traversal
void bfs(Graph& graph, int s, vector<int>& dist) {
    vector<bool> visited(graph.V, false);
    dist[s] = 0;
    visited[s] = true;
    queue<int> q;
    q.push(s);
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (int v = 0; v < graph.V; v++) {
            if (graph.adj[u][v] != INF && !visited[v]) {
                dist[v] = dist[u] + graph.adj[u][v];
                visited[v] = true;
                q.push(v);
            }
        }
    }
}
int main() {
    int N;
    cin >> N;
    Graph graph(N);
    for (int i = 0; i < N - 1; i++) {
        int u, v, w;
        cin >> u >> v >> w;
        u--;
        v--;
        addEdge(graph, u, v, w);
    }
    int M;
    cin >> M;
    for (int i = 0; i < M; i++) {
        int S, F, P;
        cin >> S >> F >> P;
        S--;
        F--;
        vector<int> dist(N, INF);
        bfs(graph, S, dist);
        int days = (dist[F] + P - 1) / P;
        cout << days << endl;
    }
    return 0;
}

