import java.util.Scanner;
import java.util.Queue;
import java.util.LinkedList;
public class Main {
    static class Graph {
        int[][] adj;
        int V;
        Graph(int V) {
            this.V = V;
            adj = new int[V][V];
            for (int i = 0; i < V; i++) {
                for (int j = 0; j < V; j++) {
                    adj[i][j] = Integer.MAX_VALUE;
                }
            }
        }
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        Graph graph = new Graph(N);
        for (int i = 0; i < N - 1; i++) {
            int u = sc.nextInt() - 1;
            int v = sc.nextInt() - 1;
            int w = sc.nextInt();
            graph.adj[u][v] = w;
            graph.adj[v][u] = w;
        }
        int M = sc.nextInt();
        for (int i = 0; i < M; i++) {
            int S = sc.nextInt() - 1;
            int F = sc.nextInt() - 1;
            int P = sc.nextInt();
            int[] dist = new int[N];
            for (int j = 0; j < N; j++) {
                dist[j] = Integer.MAX_VALUE;
            }
            bfs(graph, S, dist);
            int days = (dist[F] + P - 1) / P;
            System.out.println(days);
        }
    }
    public static void bfs(Graph graph, int s, int[] dist) {
        boolean[] visited = new boolean[graph.V];
        dist[s] = 0;
        visited[s] = true;
        Queue<Integer> q = new LinkedList<>();
        q.add(s);
        while (!q.isEmpty()) {
            int u = q.poll();
            for (int v = 0; v < graph.V; v++) {
                if (graph.adj[u][v] != Integer.MAX_VALUE && !visited[v]) {
                    dist[v] = dist[u] + graph.adj[u][v];
                    visited[v] = true;
                    q.add(v);
                }
            }
        }
    }
}

