let idx = 0;
// Structure to represent a graph
const Graph = class {
    constructor(V) {
        this.V = V;
        this.adj = Array(V).fill().map(() => Array(V).fill(Infinity));
    }
};
// Function to add an edge to the graph
function addEdge(graph, u, v, w) {
    graph.adj[u][v] = w;
    graph.adj[v][u] = w;
}
// Function to perform BFS traversal
function bfs(graph, s, dist) {
    const visited = Array(graph.V).fill(false);
    dist[s] = 0;
    visited[s] = true;
    const q = [s];
    while (q.length > 0) {
        const u = q.shift();
        for (let v = 0; v < graph.V; v++) {
            if (graph.adj[u][v] !== Infinity && !visited[v]) {
                dist[v] = dist[u] + graph.adj[u][v];
                visited[v] = true;
                q.push(v);
            }
        }
    }
}
// Input reading
const N = parseInt(input[idx++]);
const graph = new Graph(N);
for (let i = 0; i < N - 1; i++) {
    const [u, v, w] = input[idx++].split(' ').map(Number);
    addEdge(graph, u - 1, v - 1, w);
}
const M = parseInt(input[idx++]);
for (let i = 0; i < M; i++) {
    const [S, F, P] = input[idx++].split(' ').map(Number);
    const dist = Array(N).fill(Infinity);
    bfs(graph, S - 1, dist);
    const days = Math.floor((dist[F - 1] + P - 1) / P);
    console.log(days);
}

